export const RTL_LANGS = ["he", "ar"];

export function getLangKey(lang: string): string {
  if (["he", "ar"].includes(lang)) return lang;
  const valid = ["en", "he", "ar", "ru", "es", "fr", "de", "ja", "zh", "ko", "th", "vi", "tl", "id"];
  return valid.includes(lang) ? lang : "en";
}
